/**
 * Results Statistics Database - A-Level, IAL, IGCSE, GCSE, FSMQ
 *
 * Sources (official grade statistics):
 * - CAIE: cambridgeinternational.org (2019-2025)
 * - Edexcel: qualifications.pearson.com (2019-2025)
 * - AQA: aqa.org.uk (2019-2025)
 * - OCR: ocr.org.uk (2019-2025)
 * - WJEC/Eduqas: wjec.co.uk (2019-2025)
 *
 * All percentages are cumulative (achieving grade or higher).
 * Updated: 2025-07-02 from ALevel_IGCSE_GCSE_FSMQ_L2Cert_Grade_Statistics_2019-2025_FIXED.xlsx
 */

export interface YearlyStats {
  year: number;
  series: "june" | "november" | "march" | "summer" | "january" | "autumn";
  aStarRate: number;
  aRate: number;
  bRate: number;
  cRate: number;
  dRate: number;
  eRate: number;
  entries?: number;
}

export interface SubjectStats {
  code: string;
  name: string;
  board: string;
  level: "A-Level" | "IGCSE" | "GCSE" | "FSMQ";
  years: YearlyStats[];
}

function y(year: number, series: "june" | "november" | "march" | "summer" | "january" | "autumn",
  aStar: number, a: number, b: number, c: number, d: number, e: number, entries?: number): YearlyStats {
  return { year, series, aStarRate: aStar, aRate: a, bRate: b, cRate: c, dRate: d, eRate: e, entries };
}

function s(code: string, name: string, board: string, level: "A-Level" | "IGCSE" | "GCSE" | "FSMQ", years: YearlyStats[]): SubjectStats {
  return { code, name, board, level, years };
}

