export const ALL_SUBJECT_STATS: SubjectStats[] = [
  ...AQA_A_LEVEL_SUBJECTS,
  ...AQA_GCSE_SUBJECTS,
  ...CAIE_A_LEVEL_SUBJECTS,
  ...CAIE_IGCSE_SUBJECTS,
  ...EDEXCEL_A_LEVEL_SUBJECTS,
  ...EDEXCEL_IGCSE_SUBJECTS,
  ...EDEXCEL_UK_A_LEVEL_SUBJECTS,
  ...EDEXCEL_UK_GCSE_SUBJECTS,
  ...OCR_A_LEVEL_SUBJECTS,
  ...OCR_GCSE_SUBJECTS,
  ...WJEC_EDUQAS_A_LEVEL_SUBJECTS,
  ...WJEC_EDUQAS_GCSE_SUBJECTS,
];

export function getSubjectStats(code: string, board: string, level?: string): SubjectStats | undefined {
  const matches = ALL_SUBJECT_STATS.filter(
    s => s.code === code && s.board === board && (!level || s.level === level)
  );
  if (matches.length === 0) return undefined;
  if (matches.length === 1) return matches[0];
  const seen = new Set<string>();
  const merged: YearlyStats[] = [];
  for (const m of matches) {
    for (const y of m.years) {
      const key = `${y.year}-${y.series}`;
      if (!seen.has(key)) { seen.add(key); merged.push(y); }
    }
  }
  return { ...matches[0], years: merged };
}

export function getSortedSubjects(board: string, level: string): { code: string; name: string }[] {
  const subjects = ALL_SUBJECT_STATS.filter(s => s.board === board && s.level === level);
  const codeMap = new Map<string, string>();
  for (const s of subjects) {
    if (!codeMap.has(s.code)) codeMap.set(s.code, s.name);
  }
  const unique = Array.from(codeMap.entries()).map(([code, name]) => ({ code, name }));
  const priority = ["Mathematics", "Further Mathematics", "Biology", "Chemistry", "Physics",
    "Economics", "Business", "Computer Science", "Psychology"];
  const getP = (n: string) => {
    const i = priority.findIndex(p => n.toLowerCase().includes(p.toLowerCase()));
    return i === -1 ? 999 : i;
  };
  return unique.sort((a, b) => {
    const pa = getP(a.name), pb = getP(b.name);
    if (pa !== pb) return pa - pb;
    return a.code.localeCompare(b.code, undefined, { numeric: true });
  });
}

export function getAvailableBoards(): string[] {
  return [...new Set(ALL_SUBJECT_STATS.map(s => s.board))];
}

export function getAvailableLevels(board: string): string[] {
  return [...new Set(ALL_SUBJECT_STATS.filter(s => s.board === board).map(s => s.level))];
}

export function getLevelsForBoard(board: string): string[] {
  return getAvailableLevels(board);
}

export function getAvailableSubjects(board: string, level: string): { code: string; name: string }[] {
  return getSortedSubjects(board, level);
}
